# Example: Compute annualized ROI with confidence-weighted value
from dataclasses import dataclass
from typing import List

CONFIDENCE_WEIGHTS = {"high": 1.0, "medium": 0.7, "low": 0.4}

@dataclass
class ValueEntry:
    category: str
    annualized_value_usd: float
    confidence: str

def compute_weighted_roi(
    total_investment: float,
    value_entries: List[ValueEntry]
) -> dict:
    gross = sum(e.annualized_value_usd for e in value_entries)
    weighted = sum(
        e.annualized_value_usd * CONFIDENCE_WEIGHTS[e.confidence]
        for e in value_entries
    )
    by_category = {}
    for e in value_entries:
        by_category.setdefault(e.category, 0)
        by_category[e.category] += e.annualized_value_usd

    return {
        "total_investment_usd": total_investment,
        "gross_annualized_value_usd": gross,
        "confidence_weighted_value_usd": weighted,
        "gross_roi_pct": (gross - total_investment) / total_investment * 100,
        "conservative_roi_pct": (weighted - total_investment) / total_investment * 100,
        "value_by_category": by_category,
    }

entries = [
    ValueEntry("hard_financial", 3_456_000, "high"),
    ValueEntry("soft_financial", 800_000, "medium"),
    ValueEntry("operational", 500_000, "medium"),
    ValueEntry("strategic", 1_200_000, "low"),
]

result = compute_weighted_roi(806_000, entries)
for k, v in result.items():
    print(f"{k}: {v:,.0f}" if isinstance(v, float) else f"{k}: {v}")
